        "heading": "**SECTION 6: OFFICIAL RULES AND AUTHORITIES**",
        "level": 2,
        "content_html": "<table>\n<thead>\n<tr>\n<th style=\"text-align: left;\">Authority</th>\n<th style=\"text-align: left;\">Plain-English Relevance</th>\n<th style=\"text-align: left;\">Testable Priority</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 31.021</strong></td>\n<td style=\"text-align: left;\">Chief executive status of the Commissioner.</td>\n<td style=\"text-align: left;\">High (Authority)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 401.052</strong></td>\n<td style=\"text-align: left;\">Exam frequency rules (5 years).</td>\n<td style=\"text-align: left;\">High (Oversight)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 82.051</strong></td>\n<td style=\"text-align: left;\">Authority to revoke/suspend licenses.</td>\n<td style=\"text-align: left;\">High (Discipline)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 84.022</strong></td>\n<td style=\"text-align: left;\">The $25,000 penalty limit.</td>\n<td style=\"text-align: left;\">High (Penalties)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><em>TIC 101.051</em></td>\n<td style=\"text-align: left;\">Broad definition of \"transacting insurance.\"</td>\n<td style=\"text-align: left;\">High (Definitions)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 4001.151</strong></td>\n<td style=\"text-align: left;\">Temporary license rules (180 days).</td>\n<td style=\"text-align: left;\">High (Licensing)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 4004.051</strong></td>\n<td style=\"text-align: left;\">24-hour CE and Ethics requirements.</td>\n<td style=\"text-align: left;\">High (Compliance)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 541.051</strong></td>\n<td style=\"text-align: left;\">Misrepresentation and \"Twisting\" rules.</td>\n<td style=\"text-align: left;\">High (Marketing)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 542.055</strong></td>\n<td style=\"text-align: left;\">Claim acknowledgment timeline (15 days).</td>\n<td style=\"text-align: left;\">High (Claims)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 463.205</strong></td>\n<td style=\"text-align: left;\">Guaranty Association protection limits.</td>\n<td style=\"text-align: left;\">High (Security)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 885.051</strong></td>\n<td style=\"text-align: left;\">Definition of Fraternal Benefit Societies.</td>\n<td style=\"text-align: left;\">Medium (Entities)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TIC 701.051</strong></td>\n<td style=\"text-align: left;\">Mandatory duty to report fraud.</td>\n<td style=\"text-align: left;\">Medium (Ethics)</td>\n</tr>\n<tr>\n<td style=\"text-align: left;\"><strong>TAC 1.47</strong></td>\n<td style=\"text-align: left;\">The 20-day response window for TDI notice.</td>\n<td style=\"text-align: left;\">Medium (Procedure)</td>\n</tr>\n</tbody>\n</table>"
